using json = nlohmann::json;
struct ExtendedEntity1 {
    int64_t id=-1;std::string uid,name,description,status="ACTIVE",category="GENERAL",subcategory,externalId,reference;
    int64_t createdAt=0,updatedAt=0,deletedAt=0,ownerId=-1,lastModifiedBy=-1,approvedBy=-1,tenantId=0;
    int priority=0,severity=0,version=1,revision=0,sortOrder=0,displayOrder=0;
    bool deleted=false,archived=false,locked=false,hidden=false,readonly=false,mandatory=false,enabled=true,visible=true;
    double amount=0.0,tax=0.0,discount=0.0,total=0.0,budget=0.0,actual=0.0,remaining=0.0,percentage=0.0,score=0.0;
    int quantity=0,stock=0,minimum=0,maximum=0,reorderLevel=0;
    std::string color,icon,thumbnail,imageUrl,attachmentUrl,permalink,slug;
    std::vector<int64_t> childIds,parentIds,relatedIds,tagIds,categoryIds;
    std::map<std::string,std::string> properties,metadata,localization,settings;
    std::map<std::string,double> metrics,numericValues;
    std::map<std::string,bool> flags,features;
    std::map<std::string,json> nestedObjects;
    double geoLatitude=0,geoLongitude=0,geoAltitude=0;
    std::string address,street,city,state,zipCode,country,region,timezone,locale,currency;
    std::string phone,mobile,fax,email,website,socialMedia;
    json toJson() const {
        json j;j["id"]=id;j["name"]=name;j["status"]=status;j["type"]="entity";
        if(!description.empty())j["description"]=description;
        if(!category.empty())j["category"]=category;
        if(createdAt>0)j["createdAt"]=createdAt;
        j["enabled"]=enabled;j["deleted"]=deleted;
        if(amount!=0)j["amount"]=amount;if(budget!=0)j["budget"]=budget;
        return j;
    }
    void fromJson(const json& j){ if(j.contains("id"))id=j["id"];if(j.contains("name"))name=j["name"];if(j.contains("status"))status=j["status"]; }
    bool isValid() const { return id>=0&&!name.empty(); }
    std::string getDisplay() const { return name.empty()?("Entity#"+std::to_string(id)):name; }
    bool isActive() const { return enabled&&!deleted&&!archived; }
};
